import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as p,c as a,e}from"./app-d59b21eb.js";const g="/assets/image-20240131221624684-f55bd106.png",t="/assets/image-20240131222557764-d2fec7f5.png",s="/assets/image-20240131222609472-60c1c047.png",n="/assets/image-20240131222620304-6a43ad6a.png",r="/assets/image-20240131222630920-6d29a6f8.png",o="/assets/image-20240131222641737-c9db7f4b.png",c="/assets/image-20240131222650944-ec6ea79a.png",m="/assets/image-20240131222701041-caa5d25e.png",f="/assets/image-20240131222709120-0eef82bf.png",d="/assets/image-20240131222717163-0b1456bb.png",l="/assets/image-20240131222726978-c8e602d9.png",_="/assets/image-20240131222815897-0874db7d.png",u="/assets/image-20240131222823176-297ad484.png",b="/assets/image-20240131222829496-c7916489.png",h="/assets/image-20240131222837193-14ad9e09.png",x="/assets/image-20240131222843248-b6825587.png",y="/assets/image-20240131222851516-a63b1a8f.png",z="/assets/image-20240131222858720-ab66edd2.png",k={},v=e('<h1 id="道氏理论二" tabindex="-1"><a class="header-anchor" href="#道氏理论二" aria-hidden="true">#</a> 道氏理论二</h1><h2 id="道氏的三种运动" tabindex="-1"><a class="header-anchor" href="#道氏的三种运动" aria-hidden="true">#</a> 道氏的三种运动</h2><p>股票的平均价格指数由三种运动构成。也许在同一个时间中就会包含这三种运动。其中首要的，也是最为重要的就是主要趋势运动：股市整体的向上或向下的运动，也就是众所周知的牛市或熊市，其持续时间也许会是几年。处于第二位的，也是最容易迷惑人的运动，就是次一级的反应运动：对于主要趋势是牛市的市场中，次一级的反应运动就是重要回调的下跌运动；而在主要趋势是熊市的市场中，次一级的反应运动就是反弹的上升运动。这些反应运动通常持续3周到数月。处于第三位的，通常也是不重要的运动，就是平均指数的日间波动。</p><p>每一位汽车驾驶员都会记得在上第一堂驾驶课时，在心、手和脚之间发生的混乱状态。教练会坐在身边，坚持要求他把观察路况和脚离开油门踩刹车这些动作连贯起来并同时完成。可是随着经验积累，使用油门和刹车已经成了一种近似的条件反射，观察路况的习惯巡最终养成，学习者再第一次尝试理解道氏的三种价格运动时。可能也会有在类似的混乱。可是迟早他们对三种运动的识别和认知几乎会成为自动的心理和视觉过程。次级的反应运动所造成的市场趋势的暂时改变，对于市场的效用就像是刹车对汽车的作用一样：它们都是对运动超速的抑制。对于造成汽车减慢和加速的油门，可以与股市的日间波动相比照，在有些交易日，日间波动会与基本趋势和次级运动同方向；而在另一些交易日，则会相反。</p><p>这三种运动会在以后的章节中分别进行讨论。由于对每一种运动的透彻理解至关重要，明智之举，是在这里先引用一些汉密尔顿几年间所写的言论片断：</p><p>“对于道氏理论，我们需要牢记在心的是股市有三种运动，即股市整体上升或下跌的波段，历时1~3年；次一级的回调或反弹，可能历时从几天到几周不等；再有就是股市的日间波动。这三种运动同时存在，酷似奔腾向前的浪潮，翻滚的波涛伴随回撤的波浪冲向岸边。也许可以这样讲，股市次级的运动使其强有力的主要运动暂停了一段时间，不过，即使我们能有所阻碍，自然规律依旧占支配的地位。”（《股<br> 市晴雨表》）</p><p>另一次，汉密尔顿对三种运动做了如下的解释：</p><p>“它们有整体的市场运动，上升或者下跌，持续时间也许为数年之久，很少有少于1年的；然后是短期的市场波段，历时为1~3个月不等。这两种运动会在一起进行，而且，很明显还会相互抵触。这两种运动又进一步被日间波动所复杂化，而日间波动是航海者在困难水域航行时需要考虑的第三种水流。”（1909年2月26日）</p><p>在25年前，这三种运动是这样叙述的：“市场中有三种运动在一起同时发生。首先一种是日间运动，主要是交易员操作的结果造成，可以叫做第三级运动；第二种运动通常持续20~60天，反映了市场投机情绪的涨落，叫做第二级运动。最后，第三种运动是股市的最重要的运动，通常会持续数年，运动的原因是来源于股票价格相对其内在价值的调整，通常称之为主要运动。”（1904年9月17日）</p><p>在1914年，有一些简短的解释：“对于已经为多年的市场观察所确认的查尔斯・H・道的‘理论’，可以再解释一次，市场同时有三种运动。首先是最为关键的主要运动，会持续1年及更长的时间；第二位的是间或发生在熊市中的反弹或者在牛市中的下跌；第三位指的就是股市的日间波动。”（1914年4月16 日）</p><h2 id="主要运动" tabindex="-1"><a class="header-anchor" href="#主要运动" aria-hidden="true">#</a> 主要运动</h2><p>主要运动就是股市整体的基本趋势，也就是广为人知的牛市或熊市，经历的时间从少于一年到几年的时间不等。正确地确定主要运动的方向是成功投机的最重要的因素。现在还没有方法来预测一个主要趋势的持续时间的长短。</p><p>尽管如此，“...主要波段的时间长度和行程范围却极大地增加了晴雨表的预测价值。没有规则来精确表示一个主要波段由多少点构成，正像也没有一个规则来确定主要运动所预期的经济扩张和萎缩的程度。”（1924年3月10日）道氏理论的批评家有时抱怨说，道氏理论要是有用的话，就应该能事先预测出市场所要到达的目的地，以及到达目的地所用的时间。按照这种逻辑，我们可以在这里向气象局提出告诉我们哪天、哪时会有多厚的暴风雪以及酷暑期的精确时间的愿望。但是，天气预报就像道氏理论一样，完全是由实践占主导，它还没有完美到如此的程度，而且，可能永远也不会达到。但是，我们却习惯于接受天气预报，习惯于知道预报的局限性的同时非常感谢这门预报的科学对即将到来的暴风雨和其他的天气变化所给予的警告。我们对道氏理论也应该持有这样的态度。</p><p>对于阅读平均价格指数的新手，容易误把主要趋势中的大的次级反应运动，当成是市场主要趋势发生变化。在这种时候，能正确地解读市场通常很难，即使是专家也如此，可是，如能认真学习研究，学习者就会培养出发现变化的能力。如果对市场心存疑问，就应该待在场外，一直等到日平均价格指数的形态给出清楚、明确的机会再进行交易。汉密尔顿曾经经常感到茫然。对于这种有时存在于每一个交易者内心的合理的疑问，汉密尔顿的下列叙述做出了最好的解释，“必须永远牢记，在股票市场中存在一个主流和无数的带有旋涡、回退的支流，而任何一个支流都有可能在一定时间内，如一天、一周，甚至更长的时间段内，被错误地认为是主流。股市是晴雨表，不存在毫无意义的运动，其运动的含义有时一直到运动本身发生了很久以后才显露出来，而更经常的是永远不为人们所知。可是如果运动根源的知识完备，就可以真正地讲，每一个运动都是合理的。”（1906年6月29日）</p><h2 id="熊市" tabindex="-1"><a class="header-anchor" href="#熊市" aria-hidden="true">#</a> 熊市</h2><p>主要趋势是熊市的市场，它是由长期的向下运动和重要的反弹上升所组成的。熊市是由各种经济弊端造成的，并且只有当那些发生的最糟的事情已经被股市价格彻底消化掉了熊市才会结束。熊市有三个主要阶段：第一阶段，是对那些在抬高价格之后所购买的股票所寄托希望的破灭；第二阶段，是由于商业的萧条和收人的减少而导致的卖出阶段；第三个阶段，是无视股票本身的价值、将优质有价证券廉价抛售的阶段，进行这种狂售的人，是为了得到现金、一定要把自己的一部分资产进行变现的人。</p><p>1921年，汉密尔顿曾经说过，在以前的25年间，平均的牛市波段是25个月，而熊市时间是17个月。换句话说，熊市的平均时间大约是牛市平均时间的70%。</p><p>熊市似乎可以划分为三个阶段：第一阶段是对前期牛市最后冲刺所寄托希望的破灭；第二阶段反映出创收能力下降和效益的降低；第三阶段是证券的廉价清仓阶段，为生活所迫必须卖出手中的证券。上述的各阶段是由股市的次级反应划分开的，而这时的次级运动常常被错误地认为是牛市的开始。对于那些理解道氏理论的人来讲，很少被这样的次级运动所困惑。</p><p>全天股票销售额对于纽约股票交易所的交易来讲，所占的比重在熊市要比在牛市时期小得多。成交量曲线的走平是熊市可能结束的显示。</p><p>汉密尔顿经常讲，华尔街古老的座右铭“绝不要在沉闷的市场中放空”，在熊市中不是个好忠告。汉密尔顿注意到在熊市中的卖出时机，正是在剧烈反弹之后成交量枯竭之时，而后活跃的下跌运动显示出熊市会继续进行。他经常阐述的观点如下：“在华尔街最常引用的陈腐老话之一，就是告诫人们永远不要在沉闷的市场中放空。这句忠告也许对的时候比错的时候多，可是对于长期持续的熊市波段，它总是错的。在这样的熊市波段中，趋势的特点是上升变得沉闷而下跌变得活跃。”（1909年5月21日）</p><p>下面是从1921年文章中摘录的片段，有些内容值得牢记：“根据道氏的古老理论，...・在熊市中的次级反弹是突然和迅速的，尤其是在市场恐慌性的下跌后，这样的表现特征更是显著。这样的测试不是在底部，而是在一定条件下市场在上升之后的表现.....此时股市会很容易变成卖出和超卖。在市场底部时的市场情绪总是极度悲观，而当开电梯的男童也开始谈论他的“放空仓位”时，专业人士们就开始<br> “背叛”公众情绪了。</p><p>“在熊市中的次级反弹，如平均价格指数在过去许多年显示的那样，具有让人惊奇的一致性，次级反弹都是在一个市场的价格线之后发生，而这个价格线是彻底检验公众对股票的吸货能力。在发生严重的市场下跌时，跌到了支撑位总会有大量的买进，以保护那些放空的账户，不会因开仓过大而无法平仓，从而促使股票反弹。股票的下跌大部分为卖空平仓和廉价的买进所抵消，可是如果股票的吸货能力不充足，股票就还会进一步缓慢下跌，通常会创出价格新低。”（1921年6月23日）</p><p>“长期能得到平均价格指数证实的经验告诉我们，在持续时间超过一年或更长时间的长期牛市运动中，对比间或发生的快速回调，上升的过程显得比较缓慢。同样，在熊市中，其反弹也自然会是快速的。”（1910年3月19日）</p><p>在这一点上，理解在下跌或者上升市场中的运行基本原理是很重要的。</p><p>在熊市中，优质股票也会同劣质股票一样受到伤害，因为人们总会出售那些以一定的价格肯定能出手的股票，以期保护那些以什么价格都出不了手的股票。在大萧条时期，从未投过机的人们不得不把很好的投资股票从他们的保险柜中拿出来，给价就卖。因为为了生存需要现钱，无论蒙受多大损失，也要把这股票换成现钱。这些人创造了“以防万一”基金，现在“真的出了万一”。也许他们更愿意出售他们的房屋和其他财产，可是却没有出钱的买主。也许他们以前借用了生命保险金，这样就迫使保险公司为获取保险单贷款的资金，贬值出售一些有价证券。也许这些人耗尽了他们银行户头里的结存，迫使银行清算其有价证券以维持储备金。这样就形成了恶性循环，迫使优质的有价证券在没有足够买家的市场上出售。换句话说，供给和需求的规律在发挥作用，当供给量大于需求量时，价格是必然下跌的。那些阅读了我们许多杰出的咨询服务公司给出的投资建议的读者，有理由感到奇怪，为什么这些公司所雇用的经济学家们会忽视和不理解熊市波段这么重要的阶段。</p><p>是什么原因能让长期下跌的股票价格结束下跌呢？《股市晴雨表》对牛市和熊市形成的整个循环给出了精彩的解释：</p><p>“现在，我们一觉醒来，发现我们的收入超过了我们的花费，钱容易挣了，空气中弥漫着投机的气息。我们从经济的沉闷和萧条时期进人了真正的活跃阶段。投机活动在高利率、工资增长和其他常见的征兆中逐渐发展。在经历数年的好时光后，链条中最薄弱的环节承受着过度的拉力，然后是断裂...在股市中和商品市场的价格中出现了萧条的预兆，随后是巨大的失业率。常常是储蓄银行的存款在增加，而用于投机的资金却处于完全缺乏之中。”</p><p>汉密尔顿告诫我们不要试图利用道氏理论去抓熊市的低点交易日：“股市的晴雨表不能告知任何人熊市转向牛市的绝对转折处。”</p><p>在1921年9月18日，当平均价格指数从熊市的低点上升了不足5个点的幅度时，汉密尔顿在为《巴仑周刊》所写的一篇文章里写道：</p><p>“我得到了要求提供股市晴雨表在预测价值方面证据的挑战，现在股市的运动，是一个最确切的例子和测验。伴随着欧洲金融的混乱状态、棉花生产蒙受的灾难、通货紧缩产生的不确定性、我们的立法者和税务人员的毫无约束的机会主义、战后的通货膨胀，如失业、在煤矿和铁路做工都拿不到多少工资，等等，这些不利因素都笼罩在现在的国家经济中，可是股票市场却已经表现得仿佛它看到了一些有利的因素。股市一直在讲，这次在1919年10月底、11月初开始的熊市，在1921年的6月20日创出了低点，当时20 种工业股票平均价格指数是64.90，20种铁路股票平均价格指数是65.52。”</p><p>然后在几天之后的《华尔街日报》上，汉密尔顿又评论道：</p><p>“不止一位记者已经在本报中撰文，提醒大家关注这不令人满意的状况，并由此发出疑问道，为什么通过对刊登在9月21日的平均价格指数的运动研究，认为应该说股市价格似乎正在为进入长期上升的牛市做好准备？能列出的所有各种理由都是悲观的论调，如德国的企业倒闭、铁路运输的价格和工资、关税和税收的不确定性，还有愚钝的国会没有考虑这些事情的常识。对这个问题的回答是，股票市场已经考虑到了一切事情，股市所包含的信息来源要比这些批评家中的任何一位所可能掌握的信息来源都广大。”（1921年9月21日）</p><p>根据上述的这些预测，此文的作者就在当时买进了一些股票和债券，就是这次的投资成功，后来为作者提供了购买一处住宅和商业投资的资金。而后者的贏利造成了适度奢侈和在政府医院中退伍军人联络站的病房之间度日的区别。这些成功的预测，激发了其后数年的对平均价格指数的研究学习，一种对原来可望而不可即的东西的寻找，成了让人神魂颠倒而又带来了赢利的消遣活动。</p><p>1921年的深秋，汉密尔顿收到一封信，询问他推断的理由。汉密尔顿解释道，成交量少，市场横盘运行，市场对坏消息的漠视和上升失败，这一切都表明最糟糕的时刻已经过去，同时，汉密尔顿感觉他的推断被平均价格指数的日间运动特点所证明。</p><p>下一页的示意图，是为研究平均价格指数在熊市的底部的运动特点而准备的。9个熊市结束部分由上到下排列，日间的运动都是按比例画出，每个低点都是以100为标记，这样，价格的上升就会自动被转换成从低点开始算起的百分比行程。</p><p>这样的排列考虑到与当时成交量之间的关系。在图中会发现，在9个熊市结束的谷底中，其中有7个包含60~90天的时期，其平均价格指数的波动范围是在平均价格指数的3%之内，虽然这种运动不一定在两个平均价格指数之间同步发生。另外两个时期大约是在5%的变化范围内。</p><figure><img src="'+g+'" alt="image-20240131221624684" tabindex="0" loading="lazy"><figcaption>image-20240131221624684</figcaption></figure><p>在其中6个熊市的谷底，在最低点之前几个月，成交量在逐步降低，而另外3个时期，把极其低靡的市场交易作为指标就会出现误导。</p><p>关于熊市结束时的双底，已有很多叙述。确实双底现象有时会在熊市的底部发生，可是如果把双底当成一个判断的指标，几乎肯定会出错。那些频繁提出双底的人们，没有考虑到在熊市中，在不是底部的地方也会有很多双底出现。对所有的在熊市中出现的双底进行察看就会发现，有一些双底确实是在价格的低点发生，可是却不是熊市的结束。这时候，平均价格指数的运动有更大的帮助，当一个平均价格指数的低点没有得到另一个平均价格指数的确认，就表明有可能发生趋势的变化，即使不具有决定性的意义，也有很重要的辅助价值。</p><p>对下跌趋势的价格运动预测似乎比上升趋势的价格运动预测要容易些。至少，抓市场的底部比抓市场的顶部肯定要容易些。</p><p>对于平均价格指数的学习者，如果能在价格从低点上升10%之内抓到市场的底部，确实是很走运。可是，在上升20%之前，对于任何熟悉道氏理论应用的人，趋势变化的显示已经是非常明显了。</p><h2 id="牛市" tabindex="-1"><a class="header-anchor" href="#牛市" aria-hidden="true">#</a> 牛市</h2><p>主要趋势是牛市的市场，股市整体向上运动，或被一些次级的回调运动打断，时间平均长达两年以上。在牛市期间，由于商业环境的改善和股市投机活动的增加，使得来自投资和投机的购买股票的需求量加大，从而促使股票价格攀升。牛市有三个阶段：第一阶段，是人们重新恢复对经济未来发展的信心；第二阶段，是股票价格对已知的公司贏利的改善与提高所作出的反映；第三阶段，是投机狷獗、通货膨胀显著阶段，股票靠人们的希望和预期支撑价格飞涨。</p><p>如前所述，道氏理论只是一个注重实际的方法，通过对记录的道・琼斯铁路和工业股票平均价格指数的日间价格波动的研究，得出对未来市场运动的有用推理。在金融投机的冒险生涯中，能理解道氏理论，没有比在熊市结束和大的牛市形成时，会更有用处的了。</p><p>汉密尔顿似乎很容易能抓到市场的底部，他不断地声称抓底比抓上升波段的顶部容易得多。对于汉密尔顿的成功，其金融方面的智慧无疑是其原因之一。可是确有其他技能稍差的人，却能在正确的时候，成功地应用道氏理论，他们没有什么特殊的知识，只是正确地理解了平均价格指数的应用。</p><p>对于牛市和熊市，人们一定要记住，在市场中，牛市第一阶段并不是明显区别于熊市的最后的次级反弹，只有经过一段时间的验证之后才能确定。同样，对于熊市的第一阶段，首先必须当成可能是牛市的次级回调。所以，只要讨论熊市的完结就一定要包含随后发生的牛市的开始。在前一章中我们讨论了熊市结束时的典型现象，而需要再次指出的是，在熊市的结束时期，市场似乎不再受进一步的坏消息和悲观情绪的影响。市场还会出现失去了在剧烈下跌之后进行反弹的能力，表现出市场已经达到一种均衡状态，投机活动处于低潮。卖方对价格的压力失去作用，可是还没有出现能抬高价格的足够需求。市场因缺乏公众的大量参与变得沉闷乏味。悲观主义盛行，没有股票红利可分，一些重要的公司通常会有财务困难，还有很明显的政治动荡。由于所有这些事情的原因，股票市场的价格走出了一个“线态窄橱区间盘整”的形态。然后，在这个“线态窄幅区间盘整”的形态被确定无疑地向上突破时，铁路和工业的平均价格指数的日间波动就会显示出确定的趋势性，上升浪的底部都依次会逐步抬高，而随后的下跌不会跌破前期最近的价格低点。只有在这时候而不是之前，一个投机买进的位置才被明显地显示出来了。这个时候需要人们具有耐心，如果在价格大幅上升之后出现大型回调，若回调不能够跌破熊市的低点，而且随后的一系列上升浪却突破了前期熊市的主要反弹的高点，这时候，就是股市比较安全的买进时机了。</p><p>有些读者也许会问，为什么在1930年的春天的次级反弹不表示出是熊市的完结和一个新牛市的开始呢？一个回答就是，学习平均价格指数的人都知道，牛市是不会以激烈的波段为开端的。还有，在熊市的初始阶段，对于下跌的25%反弹，甚至100%的反弹都不是没有先例的。关于牛市的开始已经有许多论述文章。下面摘录的一段文章正是讨论牛市从很低的基价开始发展起来的：“前期熊市的下跌，已经使有价证券的价格远远地向下脱离了其被承认的内在价值。这是由于股票交易所提供了一个可以以一定价格买卖股票的市场，而其他的东西在这个市场中已经完全消失了。这是股票市场晴雨表的部分作用，股票市场一定是第一个感受到大清仓的压力。</p><p>“在牛市的第一阶段，是股票对其公认价值的回归阶段。在牛市的第二阶段，通常也是历时最长的阶段，是随着总体经济的好转，股票进行其价值的调整并趋于更加稳定，这个阶段也是在牛市中最能频繁见到的，历时最长，也会出现最能使人上当受骗的次级回调。牛市的第三阶段，公众的信心不仅消溶了股票的现有价值，还消溶了对未来可能性的期望。”（1923年6月25日）</p><p>下面的段落表明，在牛市缓慢的攀升阶段不但需要人们的耐心，还需要有勇气坚持经受住对于一个健康牛市所进行的快速的次级回调反应运动。“长期的，能得到平均价格指数证实的经验告诉我们，在持续时间超过一年或更长的时间的长期牛市运动中，对比间或发生的快速回调，上升的过程显得比较缓慢。同样，在熊市中，其反弹也自然会是快速的。”（1910年3月19日）</p><p>那些在华尔街具有“可操胜算的赌注”的人士，他们的生意就是在股票低于其价值时进行买进，或者是在低于合理的未来期限内将具有的价值买进股票，并且最终要在较高的市场价位卖出。如果这些拥有“可操胜算的赌注”的人士有才智和技能这样做，他们就如同一个商人所为，一个商人会在像床单布和其他棉花制品等常备商品价格低廉时，以及生产厂家因为生意的萧条而减价时，大量购进。这个商人期待着在随后的时期里，当所购商品价格上涨时卖出。当华尔街的精英分子考虑到股票价格已经跌到股票的内在价值之下，评估了成功的机会和赢利的能力后，就会在暗中悄悄地开始买进股票。渐渐地大众认识到股票价格不再走低，意识到悲观情绪与困窘已经迫使股票价格过度下跌。然后，公众开始购买股票，优质股票的流通供应量在减少，股票价格上升，牛市就已经形成了。然而，汉密尔顿告诫我们，股市主要趋势的反转从来就不会是突然间发生的。因为“构成股市主要运动的上升和下降的条件实际上永远不会一夜之间自己改变，可是促使第一次的回调和反弹的发生条件确有可能发生”。（1910年7月29日）</p><p>这里对于道氏理论这方面的讨论，是要确定道氏理论对于交易者的实用性，而不是用于经济预测的手段。作者无意于去冒昧地对汉密尔顿的杰出著作《股市晴雨表》进行改进，汉密尔顿在《股市晴雨表》中写道：“平均价格指数的运动可以作为经济晴雨表。可是对于那些能学习道氏理论并应用于投机的人们，同时也会认识到道氏理论能作为经济趋势的可靠指标。”</p><p>汉密尔顿承认在抓市场的顶部时通常会遇到困难。他写道：“..・正确地预测市场的顶部比底部要难很多。在经过长期的熊市之后，平均价格指数和认定的实际收益价值之间，股息红利和资金价值之间的背离会很明显地显现。可是，在经过长期上升之后，许多股票会仍在其内在的价值范围内买卖，有很多还没有被消溶的可能性。还有，也许是因为环境的复杂性，或者更真实地讲是由于晴雨表对未来总体的憧憬和预期的稳定，市场价格会在距离顶部很小的范围内不定期地波动。确实可以这样说有这样的例子，市场在距离顶部很近的区间范围内波动了近一年，然后才猛烈下跌形成熊市。”（1926年2月15日）</p><p>另一次，汉密尔顿写道：“...正确地预测主要运动的精确顶部已经超出了任何晴雨表的能力范围。当缺乏过度的市场投机时，更增加了预测的难度。”（1923年6月13日）按照汉密尔顿所言，若没有了过度的投机活动，即使是一个合格的平均价格指数的学习者，也会很容易地认为一个下跌的运动只不过是牛市的次级回调而已，可后来却被证实是熊市的第一次下跌。</p><p>汉密尔顿喜欢用华尔街的格言来清晰明确地表达他的观点。一次在接近市场顶部的平均价格指数讨论中，汉密尔顿写道：“华尔街经验丰富的交易员说，当开电梯的男孩儿和皮鞋匠都在寻求透露市场的牛市消息时，这就是该卖出和结束仓位去钓鱼的时候了。”在许多牛市接近尾声时，汉密尔顿经常警告他的读者说：“没有树木会长到天上去的。”</p><p>在1929年的春天，牛市的最后一冲之前，汉密尔顿承认从平均价格指数看，毫无疑问牛市在继续攀升，可是他明显地在警告他的读者，要把股市的利润落袋为安，平仓离场。汉密尔顿写道：“研究者应该问问自己，人们是不是在以比其价值高出许多的价位购买股票，人们是不是基于期望而购买股票，而且已经等待得心慌手痒。”（1929年4月5日）</p><p>在20年前的1909年，在股市达到其最高点的前几天，汉密尔顿提醒呼吁道：“必须永远不能忘记，虽然国家经济空前繁荣，可是股市的价格不会永远上升。对于一个至少是部分由于飞涨而创出历史新高的上升运动，当其头部沉重而发生市场崩溃，是通常的不可避免的市场反应。”（1909年8月24日）</p><p>汉密尔顿多次表达了他的信念：“......即使经济依然看好，市场最终会转向（下跌），而经济不久也会转向。”（1922年4月6日）经济学家们指出，在1929年股市牛市终结之前，经济已经衰退了。也许这是真的，但是，与给其他市场的锅炉施加的压力相比，牛市给股票市场这个锅炉施加了更大的压力。不管是否能证明股市在预测1929年经济的转变具有可靠性，毫无疑问的事实是，股市在10月的的确确地给出了股票价格的运行趋势已经反转的证据。那些有足够能力应用道氏理论，学会成功地交易次级反应运动的学习者，就会在9月份平掉他们的股票仓位。许多人都这样做了。那些没有平仓的人，真希望他们对比自己以前的判断，毫无例外地能多信任道氏理论一些。</p><p>从1897年开始的道・琼斯平均价格指数的全部牛市记录来看，再也没有比平均价格指数在1929年表现出的顶部反转简明易懂的了。</p><p>所有的通货膨胀的迹象都呈现出来了。股票成交量超大；经纪人贷款创新高，实际上是经常创新高；短期拆息非常之高，使得许多公司都发现有利可图，把库存变现，然后把所得现金注人华尔街以牟取暴利；有很多不光彩的联合投机活动发生；缴纳交易手续费的办公室外挂着“请站立等候”的提示牌；领先股票的派发红利要比最好的债券差；垃圾股也像坐火箭一样飞上了天，不管其内在的价值和贏利的能力；整个国家都处在股票狂热的投机中。交易老手们回忆起那几个月，奇怪于自己怎么会好像被“新时代”的观念打了麻醉针一样，在必然的股市崩盘中被套。那些很明智的银行家本来可以让投机者倾听他们的意见而解救危局，可是却被当成鼓吹破坏的坏分子而被声浪所淹没；而另外一些以“诈骗犯”载人史册的人，在当时却被赞扬为超人。</p><p>如此的市场骚动也没有动摇道氏理论。在1929年的春天，平均价格指数显示，股票的供给和需求是相等的，这就是说有重要的势力在大量卖出手中的股票，而其他的势力在吸货。然后，平均价格指数又宣告买方的力量已经超过了卖方的力量，两种平均价格指数都创出新高，股票市场在攀升的途中快乐地向上跳跃着。道氏理论指出锅炉里已经有了足够的蒸汽来推动股票价格再次上扬。</p><p>在5月12日到6月5日之间，股市发生了很像是大型下跌的运动，可事实上，成交量在股票上升时是趋于增加，而在股票价格下跌时却在减少。用道氏理论对这种现象的解释，说明这次运动不过是一次牛市中的次级回调而已。</p><p>在1929年9月3日，股市达到了牛市的价格顶点。在9月3日到10月4日之间，又发生了一次价格下跌，看来似乎只是又一次的牛市中的回调。可是，随后在10月5日发生的上升运动中，股票的成交量在降低，而且，在随后的8个交易日中，道氏理论的学习者都能从走势图中看出，在市场这个锅炉里的蒸汽已经不足以推动价格的进一步上升，因为在股价上升时，其成交量却在持续降低。当时图表专家们注意到，市场的回升只达到了可以说是熊市反弹的较低限度的水平。这样，对于道氏理论的应用者而言，已经有了明确的出货信号，就是在工业平均价格指数在350价格水平时出货，此出货价位离最高点相差不到10%！而对于那些没有出货的人，市场每天都在给出更为强烈的警告，因为成交量随着股价的下跌不断增加。而在10月20日结束的那一周，市场终于跌破了在10月4日的价格低点时，对于能读懂平均价格指数的人来讲，股市已经毫无疑问地定论成熊市了。</p><p>汉密尔顿笔下对市场主要趋势变化的最后一次预测，就是他明确地宣布了1929年9月开始的大熊市的到来。随着平均价格指数的形态一天一天地显现，汉密尔顿对之有了很明显的不祥之感。一篇登载在1929年9月23日《巴仑周刊》上的研究价格运动的文章说，平均价格指数形成了前面提到的一个线态窄幅区间盘整的形态。在1929年10月21日，《巴仑周刊》提醒到，到那时为止的一系列的上升和下降波动的意义富有熊市的意味。在1929年10月25日，一篇现在已经是非常著名的名为《趋势的反转》的评论文章刊登在《华尔街日报》上：从9月份以来的市场下跌，很明显是熊市的第一阶段。汉密尔顿在几周后突然辞世，应该讲，他最后一次关于市场趋势的预测是他最为杰出的一次股市预测。</p><h2 id="次级反应运动" tabindex="-1"><a class="header-anchor" href="#次级反应运动" aria-hidden="true">#</a> 次级反应运动</h2><p>为便于讨论，我们把在牛市中的重大下跌运动，或者在熊市中的重要上升运动，认为是次级反应运动。次级运动的持续时间通常是3周到数月不等。这种间歇性的次级反应运动的价格回调，一般会回调到其前期从前一个次级反应运动结束开始的主要趋势运动价格变化行程的33%~66%之间。这些次级反应运动常常让人们错误地以为是主要趋势发生了改变，明显的原因在于，那就是牛市第一阶段的价格运动，与后来被证实只是熊市中的次级反应运动，总是具有巧合的相似性。反过来讲，在牛市中，对于前期高点被达到之后的回调运动，和熊市第一阶段的价格运动，也总是具有巧合的相似性。</p><p>次级反应运动对于股票市场必不可少，就像蒸汽锅炉不可缺少安全阀一样。次级运动对于保证金交易者会构成最大的危险，同时，对于能识别次级运动，而不与趋势的反转相混淆的平均价格指数的学习者，也可能提供最好的获利机会。汉密尔顿说：“次级反应运动是牛市运行的维护措施之一，它对市场的过度投机是最有效果的检查。”</p><p>当市场在进行次级反应运动时，经常被问的问题是：“次级运动将会走多远呢？”就平均价格指数而言，合理和保险的说法是：对于重大的次级反应运动，一般是从主要趋势被打断后的趋势行程的1/3~2/3，或者更多。这样的概括具有极大的利用价值。可是，如果想要给次级运动以精确的限度，那就注定要失败，就像气象人员要精确地预报某一特定时刻的降雪厚度会是3.5英寸一样会失败。气象人员一般会正确地预报将要发生的有雪天气和大约的日期，可是却不能成功地预测出暴风雨出现的时刻和降雪的厚度。道氏理论的研究者和气象人员的情况是类似的。</p><p>造成市场次级反应运动的原因有许多，其中最为重要的原因是在熊市中的超卖和在牛市中的超买。这种超卖和超买的状况随着市场主要趋势的发展会加重，这常常被认做是市场的“技术状态”。次级反应运动的发生常被归咎于某一特殊的消息，可是真正的原因是市场本身的薄弱，使得市场容易产生次级反应运动。</p><p>随着一个健康牛市的发展，公众会更大量地参与购买股票。这样的购买动因是希望在更高的价格卖出股票，可是，未来总会有一天股票市场会出现卖方大于买方。那些专业交易者总是密切关注这种情况的出现，然后就尽力在市场中放空，使市场充满了卖空仓位，同时，那些跟风买进的可怜的人们在惊恐中卖出了他们的股票，这样就对趋势的反转起了推波助澜的作用。专业交易者和大众的合力卖出，造成股票价格剧烈地下跌。一个历时多个星期的牛市经常会有许多天的回调。这样的激烈下跌，会暴露出市场中一些位置不佳的买进仓位，导致其微利平仓而出场。如此的结果，是股票被打压到那些精明敏锐的交易者为开始他们下一次上升进行积累买进仓位的价格水平。</p><p>在熊市中，情况正好相反。那些愿意和需要持有现金的人们不断地清算其有价证券，导致市场报价日日走低。而专业人员意识到市场向下的空间比向上的发展空间大时，他们的卖出加速了市场的下跌。最终市场被打压到了抵押担保的价值之下。市场的卖空兴趣也许是太过度了，精明的交易者认识到，市场的清算，至少是在这个时候，已经到头了。正如平均价格指数所验证而表现的那样，他们开始为必然的周期性的反弹积累仓位。在1910年7月29日，当出现这样的情况时，汉密尔顿写道：“正常的回调上升运动似乎现在已经开始，下跌行程的40%将会被快速收复。但反弹之后若市场变得沉闷，绝大多数专业人员就会卖出股票，理论根据是，市场现在还没有足够的买方力量使真正牛市波段的假设成立。”</p><p>报纸上对这样的股市状况通常报道为“卖空逃亡”。卖空者快速地平仓，而且经常转为短线买进，再加上那些不明智的投资买进，导致整个市场急速上升。这样的上扬一直持续到市场的买进力量减弱，即那些在拐点处买进的人获利平仓时。古老的供给和需求规律继续不可阻挡地发挥作用，股价再次下跌，直到需求超过供给为止。在恐慌和半恐慌的下跌中，银行和其他的力量一般会买进一些股票来支撑市场，然后在股价上升中，再小心谨慎地卖出这些股票。在1909年5月21日汉密尔顿评论过这样的情况：“股市成交量的减少有多种含义，在华尔街常被引用的最为老生常谈的信条，就是决不应该在沉闷的市场中卖空。此忠告也许经常来讲，对的时候多于错的时候，可是在长期持续发展的熊市中，这个信条永远是错的。在熊市中，上升会变得沉闷，而下跌却十分活跃。”</p><p>次级反应运动总是让人迷惑，汉密尔顿在表达他的困惑时，经常这样强调：“牛市中的次级反应运动很难猜测，甚至其表现有时会容易使人上当。”次级反应运动频繁地提供了许多就像从牛市转为熊市的主要趋势反转的特征。正是由于在交易者的心理上也存有同样的混淆，才使次级反应运动起到对整个的市场极具价值的保险作用。在1924 年9月11日，谈论到次级反应运动时，汉密尔顿声称：“对这个问题20多年讨论的经验告诉我们，市场中的次级反应运动，其本身外在的表现，不是受那些从牛市主要运动的特征得出的规律所支配的。牛市中的次级反应运动只是在方向上与熊市相似，而实质上却有所不同。”在牛市中，当上升受到的压力过大时，就会有次级反应运动发生，就像沸腾的蒸汽锅炉在压力超过安全系数之前，从安全阀中排压一样。在1922年11月3日，汉密尔顿对此点做了如下说明：“在研究一个没有经验主义和江湖骗术的科学体系中，牛市中存在次级反应运动的原理是不应该被忽视的。在这里曾经说明过，市场发展导致的次级反应运动，在其发生之前是不可能被预知的。次级反应运动对清除市场中过量的买人仓位有显著的效果。所以市场在进行它最有价值的服务功能，就是让市场价格撤回到了更安全的水平线上，直到市场所固有的，还不能肯定判断的不利征兆被彻底明确理解为止。的确，几乎可以说，对熊市的理解就是熊市的消溶。”</p><p>熊市中的平静，交易清淡的时候，一般是放空的佳机，而且，随后一般会发展成重大的下跌运动。然而，在市场已经经历了猛烈的下跌之后，伴随这种下跌运动，市场会进入半恐慌性的崩盘阶段，而此时回补空头仓位是明智之举，甚至还可以新开多头仓位。另一方面，当平静而坚挺的市场出现交易的活跃性和上升的力度时，就可以购买股票，在随后的市场动力和交易活跃性仍然在不断增加时平仓，或者是在成交量放大而市场却不再进一步上升时平仓。可是，如果一个投机者在牛市中放空，就只是在猜测交易次级反应运动，这样的卖空，贏利的可能性极小。对他而言，好得多的方法是在上升波段的贏利之后，然后在市场回调时待在场外，等待回调之后的必然的交易沉闷期的到来，这时候再进场做买进交易。回调之后的交易沉闷期，给了业余交易者能同有经验丰富的专业交易人员一起同路交易的机会。</p><p>次级反应运动具有一些人们可以识别和确认的特征，可是还有另一些次级反应运动的特征就连交易专家也难以预期。人们普遍认为，对于次级调整的起始点，根本不可能在任何精度上进行确定。任何与主要趋势方向相反的日间运动都有可能是次级调整的开始。经常是在股市处于恐慌和半恐慌的暴跌时，伴随着稳定、持续的成交量的增加就可以确定是反弹的开始，可是成交量的顶点和极限，也许是在主要趋势运动的最后一天达到，或者是在反弹的第一天或第二天达到。对于次级调整，一个确定的特征是这种逆主要趋势的运动的速度总是要比前期的趋势运动快。汉密尔顿注意到了这点，他说：“在熊市中的反弹倾向于猛烈和不确定性。对于反弹行程所占用的时间，要比下跌这段行程时所用的时间要短。在牛市中，其回调特征也是如此。”经常一个趋势运动运行几周时间的行程，会在几天内回撤完。平均价格指数的研究者，通过察看过去几年的平均价格指数图，就可以看到类似的运动，这样也就使他们能够以一定的精确程度来确定次级调整和趋势运动之间的区别。在牛市的顶部，当平均价格指数转而下跌时，却让人怀疑不会有明显猛烈的下跌；另一方面，对于随后都被证明是一个新的牛市的开始的熊市底部的上升波浪，一般具有缓慢上升的同时带有频繁的小幅回调的特征，而且在下跌中成交量在明显降低。</p><p>如若在过去的几天中，铁路和工业平均价格指数不再在方向上相互印证，常常可以预示次级反应运动就要到来。可是这种特点不能当做规则来用，因为在绝大多数牛市的顶部和熊市的底部，也会有这样显著的特点。</p><p>关于次级反应运动，汉密尔顿在1921年12月30日的文章中写道：“华尔街的一句古老格言是：‘绝不要在沉闷的市场中卖出。’熊市中的反弹是猛烈的，可是对于有丰富经验的交易员来讲，他们会在反弹之后市场变得沉闷时，再度出击卖空。相反地，在牛市中，情况也是如此，交易员们会在市场经过回调的调整之后，变得沉闷时买进股票。”</p><p>市场重大的次级反应运动会走出一个形态，逆势运动分2~3个阶段完成，而且当然地，工业和铁路平均价格指数通常会互相确认彼此的运动。下面就对平均价格指数，包含在次级反应运动的上升和下跌波段运动，进行举例说明：</p><p>牛市中的一个一般典型的次级反应运动，就是在经历了1928年5月4日之前的长期上升之后进行的。在1928年5月4日，工业平均价格指数到达了220.88，铁路平均价格指数在5月9日达到147.05 的高点，在5月9~14日之间，两个指数没有互相确认。到了5月22日，工业指数下跌到211.73，铁路指数下跌到 142.02，随后到6月2日是一次反弹上升，工业指数升到了220.96，可是铁路指数却在144.33就停止了上升。到6月12日，工业指数跌到了202.65，铁路指数跌到了134.78。然后到6月14日，又是两个交易日的上升，工业指数达到 210.76，铁路指数达到 138.10。然后到6月18日，工业指数跌到 201.96，铁路指数跌到133.51。可是其间的成交量却在持续降低，在最低点只比100万股多一点，而许多个月以来，成交量在200~400万股都很平常。这次下跌在普通的次级反应运动的范围内就结束了。</p><p>在1931年的6~7月间，平均价格指数走出了熊市中的典型次级反应运动。从当年的2月24日开始到6月2日的长时间下跌，使工业指数从194.36跌到121.70，铁路指数是从111.58跌到了6月3日的66.85。在接近低点的过程中，成交量在持续地增加。到6月4日，工业指数上升到了134.73，铁路指数在随后的一天达到了76.17。然后，在6月6日，工业指数下跌到了129.91，铁路指数跌到了 73.72。跟着是反弹上升，到了6月13日，工业指数和铁路指数分别达到了137.03和 79.65。到了6月19日，指数价格分别跌到了130.31 和 74.71。之后，发生了调整的最后一次上升浪，使得到了6月27日，到达了反弹调整的高点：工业指数为156.93，铁路指数为88.31。成交量曲线在到达调整顶点之前的几天就显示交易在减少。这次次级调整持续了4周，工业指数和铁路指数分别回调了从2月24日开始的下跌行程的45%和 48%。2月24日的价位是上次反弹的高点。</p><p>牛市中，次级反应运动的一个一贯性的特点，就是当回调到最低点时，一般会伴随有相当大的成交量。然后，市场会上升1<sub>2天，同时成交量会保持或有少许减少。随后又是下跌，可是却没有跌破前期低点，如果成交量在这次下跌中出现减少，就可以认为次级回调已经完成，上升的趋势运动会重新启动。假如次级反应运动是在正常的回调范围内进行，其回调范围，应该是前期重大的次级回调结束后，开始主要趋势运动行程的33%</sub>66%之间。</p><p>在本章后面有对次级反应运动范围的百分比的详细分析。</p><p>有非常重要的一点需要强调，那就是每一个交易者在观察次级反应运动时，一定要始终考虑成交量的因素。成交量并不像其他特征那样具有统一的含义，可是在决定牛市中调整的安全买入点和熊市中的应该卖出点上，却很有价值。</p><p>每当股票价格在熊市中被打压出新低点，或在牛市中创出新高时，人们通常会肯定地假设市场在趋势的方向上会保持相当长的时间；可是每一个交易者都应该记住，从这样的市场价格的新顶峰和新谷底，也许会发生让人吃惊的、快速的次级反应运动。本章后面将附有次级调整运动的运动范围。次级反应运动是不可避免、必然发生的，对于次级反应运动及其历经时间可以给出很怡当的定义。一般次级反应运动的完成时间是需要3周到3个月不等，这期间却是保证金交易者的焦虑期。这期间会出现大家都知道的“双底”或“双顶”。通过趋势运动与调整的转折点和次级调整运动可能发生的范围，就可以确定一个价格调整运动的界线，只要价格运动处在这个确定的界限之内，交易员一般会“无所事事”。在调整时期，常会出现“线态窄幅区间盘整”形态。</p><p>比较而言，次级调整运动易于描述，却难以精确地定义。有时它会以“线态窄幅区间盘整”开始与结束，有时却不是如此。如果前期主要趋势运动进行得缓慢，随后的次级反应运动就会快速进行，伴随有“线态窄幅区间盘整”出现，这对于每一个超过8周的次级反应运动来讲都是相当一致的特征。</p><p>许多年以来，汉密尔顿就次级调整运动的时间和范围进行了大量的讲述。细心研读汉密尔顿全部文章的人会发现许多关于典型次级调整运动特征的文章。下面摘录的片断就是汉密尔顿对次级调整运动的代表性看法。</p><p>几年前，汉密尔顿写到，对于次级反应运动，“它倾向于过度反应，过去25年的股市记录表明，通常下跌趋势的反弹调整经常是会反弹到下跌行程的60%。在这样的反弹中，那些为支撑市场的强大集团派发了他们因支持那些弱势人们所买进的股票。随后市场的表现就取决于对这些股票的吸收能力。在这个几乎是自动的反弹之后，紧跟的是半恐慌性爆发，股票通常又被卖出，慢慢地，一天一天地，一般会跌回到第一次创出的低点价位。这不一定是主要趋势运动结束的标志，虽然这样的情况也时有发生。”（1926年4月4日）</p><p>“在经历了剧烈的下跌凸显出真正股市恐惧之后，平均价格指数总是会有一个规则的反弹运动，大约要反弹到下跌行程的40%~60%之间，然后因出于保护市场而买进的股票的卖出，股价又会下跌。”（1907年12月25日）“</p><p>已经发现，市场在剧烈的下跌之后，会伴随有40%或更多些的反弹上升，其反弹的速度比起前期的下跌来较为缓慢，由上下方向来回细小的波动构成，就像一个钟摆，在达到平衡时才停歇下来。这是在恐慌性股市崩溃之后的常有现象。”（1910年9月20日）</p><p>“多年的测试表明，平均指数在经过长期上涨之后的下跌，一般会跌到上升行程的一半位置，然后市场就在前期低点和高点之间来回运动，一直到产生新的驱动力”（1906年4月16 日）</p><p>上面的言论是汉密尔顿在对次纵调整运动进行的许多研究工作中得到的灵感，而且毫无疑问地证明了汉密尔顿的观察是正确的。这项研究完全是基于对这样一个事实的认识，也就是，任何人想用精确的数学来解释道氏理论关于次级反应运动的时间和范围都会失败。道氏理论，如前所述是实践性的学问，不能用数学的计算来定义。可是，正像气象局的许多年的天气记录有助于天气预报一样，把对次级反应运动的时间和范围的观察进行列表记录，对研究未来的市场运动有一些用处。</p><p>对道・琼斯公司记录的过去35年发生的铁路和工业股票平均价格指数波动的重大次级反应运动进行选择和排列成表，可能没有两个研究者会就选取的标准达成统一意见。本书的作者曾经尝试用多种方法对次级调整进行分类，每种方法都需要许多星期的枯燥单调的工作，可是没有一种方法能产生让人完全满意的结果。作者曾经做过这样的实验，把运行时间不足15天的所有认定的次级调整都忽略不计，结果是很多真正重大的次级反应运动被省略，而一些不重要的次级反应运动却保留下来。这样就不再考虑用时间因素划分，而考虑把平均价格指数变化在5%之内的次级反应运动省略掉，然后提高到7.5%~10%，可是应用这些方法总是使一些真正重大的次级反应运动被省略，而一些不重要的小的次级反应运动却保留下来。最终，他开发出了一个选定方法，由于此法太复杂，难以在这里细讲。用此法似乎可以忽略小的次级调整，而保留下重大的次级调整运动。表1统计了过去35年间工业股票平均价格指数的上升和下跌波段。从表1的日期和价格中分列出来的表2和表3，详细地显示了牛市和熊市的主要趋势运动和次级调整运动。把这些数据加以综合和平均，得出下列结论：</p><p>在熊市中，主要运动的平均时间是95.6天，而次级反应运动平均是66.5天，或者是69.6%的前期主要运动所用时间。在牛市中，主要运动平均是103.5天，次级运动是42.2天，或40.8%的主要运动所用时间。</p><p>汉密尔顿常讲，次级反应运动一般用时是3周到数月。在检验这条规则时，发现在熊市中，次级反应运动的65.5%是在20<sub>100天结束，平均是47.3天。其中，占全部次级调整的45%的次级反应运动，在25</sub>55天就到达相反运动的极点。在牛市中，相应的数据显示，在次级反应运动中，有比在熊市中较小的百分比，即60.5%是在20<sub>100天之间完成的，平均是42.8天，总共占总数的44.2%的次级反应运动所用时间是25</sub>55天。</p><p>汉密尔顿常说，他相信次级反应运动一般地会回调其先前的主要运动价格变化程度的40%~60%。在检验汉密尔顿的信条时发现，在熊市中，把全部的次级反应运动平均起来算，平均调整量是前期进行趋势运动行程的55.8%。其中，有占72.5%的次级调整运动，其反弹量要大于前期主要运动的1/3或小于2/3。把全部的反弹波段平均来算，是达到前期主要趋势运动行程的49.5%。</p><p>对于牛市，相应的数据如下：全部的次级回调量平均占前期趋势上升的58.9%，可是只有50%的回调在前期上升量的1/3~2/3之间结束。对于这样结束的回调运动，平均回调量是前期上升行程的54.9%。</p><p>看来对于次级反应运动，在熊市和牛市中，有足够多的相似性特征，可以把它们作为一个整体考虑，而不是把在熊市和牛市中的次级反应运动作严格的特征区分。按这种方法统计发现，全部的主要趋势运动在进行重大的次级反应运动之前，平均运行100.1个交易日，全部的次级反应运动平均时间是52.2天，其平均调整幅度是其前期趋势运动的57.6%。</p><p>如果我们能说，对于重大、主要的次级反应运动结束于趋势行程量的57%，那么投机就将会是件容易的事。不幸的是，经过详细的分析：全部次级调整运动的7.1%在回撤到前期主要趋势运动的10%<sub>25%就结束了；有25.4%的次级调整运动在回撤了25%</sub>40%后结束；有18.8%的次级调整运动是在回撤了40%<sub>55%后结束；有26.7%的次级调整运动是在回撤了55%</sub>70%后结束；有8.5%的次级调整运动是在回撤了70%~85%后结束；还有14%的次级调整运动是在回撤超过了85%后才结束。</p><p>当考虑次级反应运动时，时间经常是有用的因素。因为有占73%的次级调整运动是在55个交易日内完成的，其中又有60%比例的次级调整运动是在25~55天结束。</p><figure><img src="'+t+'" alt="image-20240131222557764" tabindex="0" loading="lazy"><figcaption>image-20240131222557764</figcaption></figure><figure><img src="'+s+'" alt="image-20240131222609472" tabindex="0" loading="lazy"><figcaption>image-20240131222609472</figcaption></figure><figure><img src="'+n+'" alt="image-20240131222620304" tabindex="0" loading="lazy"><figcaption>image-20240131222620304</figcaption></figure><figure><img src="'+r+'" alt="image-20240131222630920" tabindex="0" loading="lazy"><figcaption>image-20240131222630920</figcaption></figure><figure><img src="'+o+'" alt="image-20240131222641737" tabindex="0" loading="lazy"><figcaption>image-20240131222641737</figcaption></figure><figure><img src="'+c+'" alt="image-20240131222650944" tabindex="0" loading="lazy"><figcaption>image-20240131222650944</figcaption></figure><figure><img src="'+m+'" alt="image-20240131222701041" tabindex="0" loading="lazy"><figcaption>image-20240131222701041</figcaption></figure><figure><img src="'+f+'" alt="image-20240131222709120" tabindex="0" loading="lazy"><figcaption>image-20240131222709120</figcaption></figure><figure><img src="'+d+'" alt="image-20240131222717163" tabindex="0" loading="lazy"><figcaption>image-20240131222717163</figcaption></figure><figure><img src="'+l+'" alt="image-20240131222726978" tabindex="0" loading="lazy"><figcaption>image-20240131222726978</figcaption></figure><p>当计算工业平均价格指数的股票数量由12种变成20种时，就人为地使工业平均价格指数的价格降低了19.84点。</p><figure><img src="'+_+'" alt="image-20240131222815897" tabindex="0" loading="lazy"><figcaption>image-20240131222815897</figcaption></figure><figure><img src="'+u+'" alt="image-20240131222823176" tabindex="0" loading="lazy"><figcaption>image-20240131222823176</figcaption></figure><figure><img src="'+b+'" alt="image-20240131222829496" tabindex="0" loading="lazy"><figcaption>image-20240131222829496</figcaption></figure><figure><img src="'+h+'" alt="image-20240131222837193" tabindex="0" loading="lazy"><figcaption>image-20240131222837193</figcaption></figure><figure><img src="'+x+'" alt="image-20240131222843248" tabindex="0" loading="lazy"><figcaption>image-20240131222843248</figcaption></figure><figure><img src="'+y+'" alt="image-20240131222851516" tabindex="0" loading="lazy"><figcaption>image-20240131222851516</figcaption></figure><figure><img src="'+z+'" alt="image-20240131222858720" tabindex="0" loading="lazy"><figcaption>image-20240131222858720</figcaption></figure>',116),B=[v];function E(H,N){return p(),a("div",null,B)}const j=i(k,[["render",E],["__file","02-道氏理论二.html.vue"]]);export{j as default};
